const __pageData = JSON.parse('{"title":"路由与导航：SPA路由的形式化","description":"从形式化角度定义SPA路由的代数结构，深入分析Hash与History模式的语义差异，并映射到React Router v6、Vue Router、Next.js及TanStack Router的工程实践。","frontmatter":{"title":"路由与导航：SPA路由的形式化","description":"从形式化角度定义SPA路由的代数结构，深入分析Hash与History模式的语义差异，并映射到React Router v6、Vue Router、Next.js及TanStack Router的工程实践。","date":"2026-05-01T00:00:00.000Z","tags":["框架模型","路由","SPA","导航","形式化","React Router","Vue Router","Next.js","TanStack Router"],"category":"theoretical-foundations"},"headers":[],"relativePath":"framework-models/11-routing-navigation-theory.md","filePath":"framework-models/11-routing-navigation-theory.md","lastUpdated":1777713329000}');
